```python
from sqlalchemy import Column, Integer, ForeignKey, Float
from sqlalchemy.orm import relationship
from db_setup import Base, SessionLocal

class User(Base):
    __tablename__ = 'users'

    id = Column(Integer, primary_key=True, index=True)
    username = Column(String, unique=True, index=True)
    email = Column(String, unique=True, index=True)
    hashed_password = Column(String)  # You should use a secure hashing mechanism in production

class Product(Base):
    __tablename__ = 'products'

    id = Column(Integer, primary_key=True, index=True)
    name = Column(String, index=True)
    price = Column(Float)
    stock_quantity = Column(Integer)

# Define the CartItem model
class CartItem(Base):
    __tablename__ = 'cart_items'

    id = Column(Integer, primary_key=True, index=True)
    user_id = Column(Integer, ForeignKey('users.id'), nullable=False)  # Foreign key to User
    product_id = Column(Integer, ForeignKey('products.id'), nullable=False)  # Foreign key to Product
    quantity = Column(Integer, default=1)

    user = relationship("User", back_populates="cart_items")
    product = relationship("Product")

# Assuming you have a CartItem relationship defined in User and Product models
User.cart_items = relationship('CartItem', order_by=CartItem.id, back_populates='user')
Product.cart_items = relationship('CartItem', order_by=CartItem.id, back_populates='product')

def init_db():
    Base.metadata.create_all(bind=engine)

if __name__ == "__main__":
    session = SessionLocal()
    init_db()  # This will create the table if it doesn't exist
```

### Step 2: Define Functions for Managing Cart Items

Define functions to add, update, and remove items from a user's cart.

#### `models.py` (continued)

```python
from sqlalchemy.orm import Session

def get_user_cart_items(db_session: Session, user_id: int) -> list[CartItem]:
    return db_session.query(CartItem).filter(CartItem.user_id == user_id).all()

def add_to_cart(db_session: Session, user_id: int, product_id: int, quantity: int = 1):
    try:
        # Check if the item already exists in the cart
        existing_item = db_session.query(CartItem).filter(
            CartItem.user_id == user_id,
            CartItem.product_id == product_id
        ).first()

        if existing_item:
            existing_item.quantity += quantity
        else:
            new_cart_item = CartItem(user_id=user_id, product_id=product_id, quantity=quantity)
            db_session.add(new_cart_item)

        db_session.commit()

    except Exception as e:
        db_session.rollback()
        print(f"Failed to add item to cart: {e}")
        raise

    finally:
        db_session.close()

def update_cart_quantity(db_session: Session, user_id: int, product_id: int, new_quantity: int):
    try:
        existing_item = db_session.query(CartItem).filter(
            CartItem.user_id == user_id,
            CartItem.product_id == product_id
        ).first()

        if existing_item and 0 < new_quantity <= existing_item.product.stock_quantity:
            existing_item.quantity = new_quantity
            db_session.commit()

    except Exception as e:
        db_session.rollback()
        print(f"Failed to update cart item quantity: {e}")
        raise

    finally:
        db_session.close()

def remove_from_cart(db_session: Session, user_id: int, product_id: int):
    try:
        existing_item = db_session.query(CartItem).filter(
            CartItem.user_id == user_id,
            CartItem.product_id == product_id
        ).first()

        if existing_item:
            db_session.delete(existing_item)
            db_session.commit()

    except Exception as e:
        db_session.rollback()
        print(f"Failed to remove item from cart: {e}")
        raise

    finally:
        db_session.close()
```

